const GLOSSARY_ECIH = [
  { term:"Botnet", definition:"A network of compromised devices controlled by an attacker to conduct coordinated activities like DDoS or spam. Identifying and isolating bots is central to network incident response." },
  { term:"CERT", definition:"A Computer Emergency Response Team that provides incident coordination, vulnerability handling, and guidance, often at a national or organizational level. CERTs disseminate alerts and best practices." },
  { term:"Chain of Custody", definition:"A documented record tracking the seizure, control, transfer, and analysis of digital evidence. Maintaining an unbroken chain preserves evidence integrity and admissibility in court." },
  { term:"CIA Triad", definition:"The core security model of Confidentiality, Integrity, and Availability. Incident handlers assess which of these three properties an incident has compromised to determine impact and prioritization." },
  { term:"Cloud Incident", definition:"A security incident occurring in cloud environments, complicated by shared responsibility models, multi-tenancy, limited visibility, and provider-controlled infrastructure." },
  { term:"Cloud Logging", definition:"The collection of activity and audit records from cloud services, such as AWS CloudTrail or Azure Activity Logs. These logs are vital evidence sources for investigating cloud incidents." },
  { term:"Command and Control", definition:"The infrastructure attackers use to remotely direct compromised hosts and exfiltrate data. Blocking C2 traffic is a priority during containment of malware and intrusion incidents." },
  { term:"Computer Security Incident", definition:"A violation or imminent threat of violation of security policies, acceptable use policies, or standard security practices. Incident handlers classify these by type and severity to guide the response." },
  { term:"Containment", definition:"The incident response phase isolating affected systems to prevent incident spread while preserving evidence. Can be short-term (immediate isolation) or long-term (network segmentation)." },
  { term:"Cross-Site Scripting", definition:"A web vulnerability allowing attackers to inject malicious scripts into pages viewed by other users. Handling involves identifying affected inputs, sanitizing them, and reviewing session compromise." },
  { term:"CSIRT", definition:"A Computer Security Incident Response Team that receives, reviews, and responds to security incident reports for a constituency. CSIRTs provide coordination, analysis, and remediation services." },
  { term:"Cyber Kill Chain", definition:"A model describing the stages of a cyberattack: Reconnaissance, Weaponization, Delivery, Exploitation, Installation, Command & Control, Actions on Objectives. Used to identify where to interrupt attacks." },
  { term:"Data Exfiltration", definition:"The unauthorized transfer of data from a system to an attacker-controlled destination. Handlers detect it through outbound traffic anomalies and prioritize containment to limit data loss." },
  { term:"DDoS Attack", definition:"Distributed Denial of Service — coordinated attack overwhelming a target with traffic from many sources, disrupting legitimate access. Requires detection, traffic scrubbing, and ISP coordination." },
  { term:"Denial-of-Service Attack", definition:"An attack that overwhelms a system or service to make it unavailable to legitimate users. Handling involves traffic filtering, rate limiting, and coordination with upstream providers." },
  { term:"Distributed Denial-of-Service Attack", definition:"A DoS attack launched from many compromised systems, often a botnet, to amplify volume and evade blocking. Mitigation typically uses scrubbing services and traffic diversion." },
  { term:"Dynamic Malware Analysis", definition:"Executing suspected malware in an isolated sandbox to observe its runtime behavior, network activity, and system changes. It reveals actions that static analysis alone may miss." },
  { term:"Eradication", definition:"The incident response phase removing the root cause of the incident — malware, unauthorized accounts, or exploited vulnerabilities — from all affected systems." },
  { term:"Escalation", definition:"The process of notifying higher-level personnel, management, or specialized teams when an incident exceeds the current responder's authority or expertise." },
  { term:"Event", definition:"Any observable occurrence in a system or network, such as a login or file access. Not every event is an incident, but adverse events may become security incidents requiring handling." },
  { term:"Evidence Gathering and Forensics", definition:"The IH&R phase of collecting, preserving, and analyzing digital evidence in a forensically sound manner. Proper handling supports root-cause analysis and potential legal proceedings." },
  { term:"False Negative", definition:"A failure to detect actual malicious activity, leaving a real incident unnoticed. False negatives are especially dangerous because they delay containment and increase damage." },
  { term:"False Positive", definition:"An alert that incorrectly indicates malicious activity when none exists. Excessive false positives waste analyst time during triage and can mask genuine incidents." },
  { term:"Fileless Malware", definition:"Malicious code that operates in memory and leverages legitimate tools like PowerShell, leaving few disk artifacts. Its stealth makes memory forensics and behavioral detection essential." },
  { term:"Forensic Preservation", definition:"Steps taken during incident response to preserve digital evidence in an unaltered state for later investigation or legal proceedings, including memory capture and disk imaging." },
  { term:"Forensic Readiness", definition:"An organization's proactive capability to collect and preserve digital evidence efficiently when an incident occurs. It reduces investigation cost and strengthens legal defensibility." },
  { term:"Identification", definition:"The incident response phase detecting and confirming that an incident has occurred, determining its scope, and classifying its severity." },
  { term:"IDS", definition:"An Intrusion Detection System that monitors network or host activity and alerts on suspicious patterns. IDS alerts are a primary detection source feeding the incident handling process." },
  { term:"IH&R Preparation Phase", definition:"The first IH&R step where the organization builds policies, teams, tools, and communication plans before any incident occurs. Strong preparation reduces response time and impact when incidents strike." },
  { term:"Incident", definition:"Any event that violates or threatens to violate an organization's security policies, acceptable use policies, or standard security practices." },
  { term:"Incident Categorization", definition:"Classifying incidents by type, such as malware, unauthorized access, or denial of service, to apply the correct response procedures. Categorization streamlines triage and reporting." },
  { term:"Incident Handling and Response (IH&R)", definition:"EC-Council's structured process for addressing security incidents from preparation through post-incident activities. It provides a repeatable lifecycle for identifying, containing, and recovering from incidents." },
  { term:"Incident Prioritization", definition:"Ranking incidents by factors like functional impact, information impact, and recoverability to allocate resources first to the most severe. It ensures critical incidents receive immediate attention." },
  { term:"Incident Recording and Assignment", definition:"The IH&R phase where an incident is formally logged, ticketed, and assigned to appropriate handlers. Accurate recording establishes an audit trail and ensures accountability." },
  { term:"Incident Response", definition:"An organized approach to addressing and managing the aftermath of a security breach or attack. The goal is to handle the situation in a way that limits damage, reduces recovery time, and minimizes costs." },
  { term:"Incident Response Plan", definition:"A documented set of procedures for detecting, containing, eradicating, and recovering from cybersecurity incidents. Must be tested regularly through exercises." },
  { term:"Incident Response Team", definition:"The designated group responsible for executing the incident response plan across detection, containment, and recovery. Members have defined roles such as lead, analyst, and communications liaison." },
  { term:"Incident Triage", definition:"The process of validating, categorizing, prioritizing, and analyzing reported incidents to allocate resources effectively. Triage separates true incidents from false positives and ranks them by severity." },
  { term:"Indication", definition:"A sign that an incident may have already occurred or is currently occurring, such as antivirus alerts or unusual outbound traffic. Handlers correlate indications to confirm and scope an incident." },
  { term:"Indicator of Attack", definition:"Behavioral evidence revealing an attacker's intent or actions in progress, such as lateral movement or credential misuse. Unlike IOCs, IOAs focus on real-time attacker techniques rather than post-breach artifacts." },
  { term:"Indicator of Compromise", definition:"A forensic artifact such as a malicious IP, file hash, or registry key that shows a system has likely been breached. IOCs are collected during detection and shared as threat intelligence." },
  { term:"Indicators of Compromise", definition:"Forensic data — IP addresses, domain names, file hashes, registry keys — that signal a system has been compromised. Used to detect infections across an environment." },
  { term:"Insider Threat", definition:"A security risk originating from current or former employees, contractors, or partners with authorized access who misuse that access intentionally or unintentionally." },
  { term:"ISAC", definition:"An Information Sharing and Analysis Center that enables sector-specific organizations to exchange threat intelligence and incident data. ISACs improve collective defense across industries such as finance and healthcare." },
  { term:"ISO/IEC 27035", definition:"The international standard providing a structured approach to information security incident management. It covers planning, detection, assessment, response, and lessons learned across multiple phases." },
  { term:"Lessons Learned", definition:"The final incident response phase conducting a post-incident review to identify what happened, what was done, what worked, what failed, and how to improve future response." },
  { term:"Long-Term Containment", definition:"Sustained measures that keep systems operational while enabling permanent remediation, such as patching or applying temporary firewall rules. It maintains business continuity until eradication is complete." },
  { term:"Malware", definition:"Malicious software such as viruses, worms, trojans, and spyware designed to harm or exploit systems. Malware incidents require detection, isolation, analysis, and thorough eradication." },
  { term:"Malware Incident", definition:"A security incident caused by malicious software including viruses, worms, ransomware, spyware, or trojans compromising system integrity, confidentiality, or availability." },
  { term:"Malware Isolation", definition:"Segregating infected systems from the network to prevent malware from spreading or communicating with command-and-control servers. It is a critical containment step in malware incidents." },
  { term:"Man-in-the-Middle Attack", definition:"An attack where the adversary secretly intercepts and possibly alters communication between two parties. Detection relies on anomalies like certificate warnings and unexpected ARP changes." },
  { term:"Mean Time to Detect", definition:"The average time from when an incident begins to when it is detected. A key metric for measuring the effectiveness of security monitoring capabilities." },
  { term:"Mean Time to Respond", definition:"The average time from incident detection to containment. Measures the speed and effectiveness of the incident response process." },
  { term:"MITRE ATT&CK", definition:"A globally accessible knowledge base of adversary tactics and techniques based on real-world observations. Handlers use it to classify attacker behavior and improve detection and response." },
  { term:"Network Scanning", definition:"Probing a network to discover live hosts, open ports, and running services. Handlers treat unexpected scanning as an early indicator warranting increased monitoring." },
  { term:"Network Security Incident", definition:"An incident affecting network infrastructure or communications, including unauthorized access, traffic interception, denial of service, or routing manipulation." },
  { term:"NIST SP 800-61", definition:"The NIST Computer Security Incident Handling Guide defining a four-phase lifecycle: preparation; detection and analysis; containment, eradication, and recovery; and post-incident activity. It is a foundational IR framework." },
  { term:"Notification", definition:"The IH&R phase of informing relevant internal and external stakeholders once an incident is confirmed. Timely notification supports coordinated response and meets regulatory obligations." },
  { term:"Order of Volatility", definition:"The principle of collecting the most transient digital evidence first, such as CPU registers and RAM, before less volatile data like disk files. It maximizes the evidence captured before it is lost." },
  { term:"OWASP Top 10", definition:"A widely referenced list of the most critical web application security risks, such as injection and broken access control. Handlers use it to guide web incident investigation and prevention." },
  { term:"Phishing", definition:"Social engineering attack using fraudulent emails to trick recipients into revealing credentials, clicking malicious links, or downloading malware." },
  { term:"PICERL Model", definition:"Preparation, Identification, Containment, Eradication, Recovery, Lessons Learned — a widely used framework for structuring the incident response lifecycle." },
  { term:"Playbook", definition:"A documented, step-by-step procedure for responding to a specific type of security incident, ensuring consistent, efficient response regardless of which analyst handles it." },
  { term:"Post-Incident Activities", definition:"The final IH&R phase covering documentation, lessons learned, and process improvement after an incident is resolved. It strengthens future preparedness and updates the incident response plan." },
  { term:"Precursor", definition:"A sign that an incident may occur in the future, such as reconnaissance scans or a newly published exploit for software in use. Incident handlers monitor precursors to enable proactive defense." },
  { term:"Preparation", definition:"The incident response phase establishing capabilities before incidents occur: policies, procedures, training, tools, and communication channels." },
  { term:"Ransomware", definition:"Malware encrypting victim's data and demanding payment for the decryption key. Response requires isolation, backup recovery, and decision-making on ransom payment policy." },
  { term:"Reconnaissance", definition:"The attacker's information-gathering phase to identify targets, services, and vulnerabilities before an attack. Detecting recon activity such as scanning serves as a precursor for handlers." },
  { term:"Recovery", definition:"The incident response phase restoring affected systems to normal operation, verifying they are functioning correctly, and monitoring for any signs of recurrence." },
  { term:"Root Cause Analysis", definition:"A structured investigation process determining the fundamental cause of an incident rather than just treating symptoms, preventing recurrence." },
  { term:"Rootkit", definition:"Stealthy malware that hides its presence and grants persistent privileged access while evading detection. Eradication frequently requires reimaging the affected system to ensure removal." },
  { term:"Runbook", definition:"An operational document detailing routine and incident-driven tasks for maintaining or restoring a system. In incident response, runbooks guide handlers through technical remediation steps." },
  { term:"Sandbox", definition:"An isolated, controlled environment used to safely execute and observe suspicious files or code. Sandboxes protect production systems while enabling dynamic malware analysis." },
  { term:"Security Event", definition:"An observable occurrence in a system or network. Not all security events are incidents — events become incidents when they negatively impact confidentiality, integrity, or availability." },
  { term:"Shared Responsibility Model", definition:"The cloud security principle dividing security duties between the provider and the customer based on service type. Understanding this split is essential for scoping cloud incident response." },
  { term:"Short-Term Containment", definition:"Immediate, temporary actions to stop an incident from spreading, such as disconnecting an infected host from the network. It buys time while a durable solution is prepared." },
  { term:"SIEM", definition:"Security Information and Event Management technology that aggregates and correlates logs to detect and investigate incidents. It provides centralized visibility and alerting for handlers." },
  { term:"SOC", definition:"A Security Operations Center that continuously monitors, detects, and responds to security events using tools like SIEM. The SOC often initiates the incident handling process upon detecting threats." },
  { term:"SQL Injection", definition:"A web attack that inserts malicious SQL through input fields to manipulate a database. Investigation includes reviewing application and database logs for anomalous queries." },
  { term:"Static Malware Analysis", definition:"Examining a malicious file's code, strings, and structure without executing it. Handlers use it to extract IOCs and understand capabilities before dynamic testing." },
  { term:"Tabletop Exercise", definition:"A discussion-based simulation where stakeholders walk through a hypothetical incident scenario to test the incident response plan without actually activating response procedures." },
  { term:"Threat Intelligence", definition:"Actionable information about adversaries including their tactics, techniques, motivations, and targets, used to improve detection, response, and prevention capabilities." },
  { term:"Triage", definition:"Rapid assessment of a security event to determine its severity, scope, and required response priority, enabling efficient allocation of incident response resources." },
  { term:"Trojan", definition:"Malware disguised as legitimate software that grants attackers unauthorized access or performs hidden malicious actions. Detection often relies on behavioral analysis and unusual outbound connections." },
  { term:"Web Application Firewall", definition:"A control that filters and monitors HTTP traffic to protect web applications from attacks like injection and XSS. WAF logs support detection and containment of web incidents." },
  { term:"Web Application Incident", definition:"Compromise of web-facing applications through attacks such as SQL injection, XSS, CSRF, or authentication bypass, requiring application-layer investigation and patching." },
  { term:"Worm", definition:"Self-replicating malware that spreads across networks without user interaction, often exploiting vulnerabilities. Rapid network segmentation and patching are key to containing worm outbreaks." },
  { term:"NIST SP 800-61 Rev 2", definition:"The NIST Computer Security Incident Handling Guide defining the four-phase IR lifecycle: Preparation; Detection & Analysis; Containment, Eradication & Recovery; and Post-Incident Activity. It is a primary reference framework for building and operating an incident response capability." },
  { term:"SANS PICERL", definition:"The SANS six-step incident handling model: Preparation, Identification, Containment, Eradication, Recovery, and Lessons Learned. It provides a linear, repeatable process handlers follow from readiness through post-incident review." },
  { term:"Cyber Kill Chain (7 stages)", definition:"Lockheed Martin's model describing intrusion stages: Reconnaissance, Weaponization, Delivery, Exploitation, Installation, Command & Control, and Actions on Objectives. Handlers map detections to stages to break the chain as early as possible." },
  { term:"MITRE ATT&CK Tactics/Techniques", definition:"A knowledge base of adversary behavior organized by tactics (the why/goal) and techniques (the how). Incident handlers use ATT&CK to categorize observed activity, drive detection engineering, and communicate TTPs consistently." },
  { term:"Diamond Model of Intrusion Analysis", definition:"An analytic framework linking four core features of an intrusion event: adversary, capability, infrastructure, and victim. It helps handlers pivot across related events and enrich attribution and threat intelligence." },
  { term:"Unified Kill Chain", definition:"An extended 18-phase model combining the Cyber Kill Chain and MITRE ATT&CK to describe end-to-end attacks including initial foothold, network propagation, and objective completion. It gives handlers finer granularity than the classic seven-stage chain." },
  { term:"Pyramid of Pain", definition:"David Bianco's model ranking indicators by how much difficulty their denial causes an adversary, from trivial (hashes, IPs, domains) to painful (tools, TTPs). Handlers prioritize detections higher on the pyramid to impose lasting cost on attackers." },
  { term:"Precursor vs Indicator", definition:"A precursor is a sign that an incident may occur in the future, while an indicator is a sign that an incident may already be occurring or has occurred. Handlers monitor precursors for prevention and indicators for detection and analysis." },
  { term:"IOC vs IOA", definition:"Indicators of Compromise are forensic artifacts (hashes, IPs, registry keys) showing a breach happened, while Indicators of Attack focus on adversary intent and behavior in progress. IOA-based detection can catch novel attacks that lack known IOCs." },
  { term:"TTP (Tactics, Techniques, Procedures)", definition:"The patterns of activity describing how an adversary operates: tactics are high-level goals, techniques are general methods, and procedures are specific implementations. TTP-based analysis is durable because adversaries change tools more easily than behavior." },
  { term:"Dwell Time", definition:"The elapsed time between an attacker's initial compromise and the moment the intrusion is detected. Reducing dwell time is a core IR objective because longer dwell allows deeper lateral movement and greater data loss." },
  { term:"Mean Time to Detect (MTTD)", definition:"The average time taken to identify that a security incident has occurred. A lower MTTD indicates stronger detection capability and typically limits attacker dwell time and damage." },
  { term:"Mean Time to Respond (MTTR)", definition:"The average time from detection to the initiation or completion of response actions against an incident. It measures the efficiency of the IR team and its playbooks in mobilizing containment and remediation." },
  { term:"Mean Time to Contain (MTTC)", definition:"The average time required to stop an incident from spreading after it is detected. Shorter containment time reduces blast radius and the scope of eradication and recovery." },
  { term:"Severity/Priority Matrix", definition:"A grid combining incident impact and urgency to assign a handling priority level. It standardizes decisions about resource allocation, response speed, and escalation across the IR team." },
  { term:"Escalation Matrix", definition:"A predefined chart specifying who must be notified and involved at each incident severity level and time threshold. It ensures the right technical, management, and legal stakeholders are engaged without delay." },
  { term:"War Room", definition:"A dedicated physical or virtual command center where the incident response team coordinates activities during a major incident. It centralizes communication, decision-making, and status tracking for complex or high-severity events." },
  { term:"Golden Hour", definition:"The critical early window after detection when swift, correct action most effectively limits an incident's spread and damage. Handlers aim to complete triage and initial containment within this period." },
  { term:"Containment Strategy Selection", definition:"The decision process for choosing short-term versus long-term containment based on criteria like evidence preservation, service availability, and resource needs. NIST recommends documenting criteria in advance to enable rapid, defensible choices." },
  { term:"Network Segmentation (Containment)", definition:"Isolating affected systems into separate network zones or VLANs to prevent an attacker from moving laterally. It is a containment tactic that limits blast radius while preserving evidence and some operations." },
  { term:"Sinkholing", definition:"Redirecting malicious traffic, such as C2 or malware callbacks, to a controlled server instead of the attacker's infrastructure. Handlers use sinkholes to disrupt botnets and identify infected hosts." },
  { term:"System Isolation", definition:"Disconnecting a compromised host from the network to halt attacker activity while preserving its state for forensics. Isolation can be physical unplugging, port shutdown, or host-based firewall quarantine." },
  { term:"Eradication vs Recovery", definition:"Eradication removes the root cause and artifacts of an incident, such as malware, backdoors, and compromised accounts, while recovery restores affected systems to normal, validated operation. Recovery should only proceed after eradication is confirmed complete." },
  { term:"Root Cause Analysis (5 Whys)", definition:"An iterative questioning technique that repeatedly asks why a problem occurred to trace an incident to its underlying cause. It prevents recurrence by addressing systemic issues rather than only surface symptoms." },
  { term:"Fishbone (Ishikawa) Diagram", definition:"A cause-and-effect diagram that visually organizes potential contributing factors of an incident into categories such as people, process, and technology. Handlers use it during post-incident analysis to structure root cause investigation." },
  { term:"Lessons Learned / After-Action Review", definition:"A structured post-incident meeting to evaluate what happened, what worked, and what should improve. Findings feed back into preparation, updating playbooks, controls, and training to strengthen future response." },
  { term:"Playbook vs Runbook", definition:"A playbook describes the strategic, decision-oriented workflow for handling a class of incident, while a runbook provides the detailed, step-by-step technical procedures. Playbooks guide what to do; runbooks specify exactly how." },
  { term:"SOAR Orchestration", definition:"Security Orchestration, Automation, and Response platforms integrate tools and automate repetitive IR tasks through codified playbooks. They reduce response time and analyst workload by chaining enrichment, containment, and notification actions." },
  { term:"Threat Intelligence Levels", definition:"Threat intelligence is categorized as strategic (high-level risk trends for leadership), operational (campaign and actor context), and tactical (specific IOCs and TTPs for defenders). Handlers apply each level to inform decisions at the appropriate scope." },
  { term:"STIX/TAXII", definition:"STIX is a standardized language for representing structured threat intelligence, and TAXII is the transport protocol for sharing it. Together they enable automated exchange of IOCs and TTPs between organizations and sharing communities." },
  { term:"MISP", definition:"The Malware Information Sharing Platform is an open-source tool for collecting, storing, and sharing threat intelligence and IOCs among trusted communities. It supports correlation, tagging, and automated feed export for IR teams." },
  { term:"OpenIOC", definition:"An XML-based framework, originally from Mandiant, for describing indicators of compromise in a machine-readable format. It lets handlers document and share host and network artifacts for detection and hunting." },
  { term:"Sigma Rules", definition:"A generic, vendor-neutral signature format for describing detections in log data that can be converted to many SIEM query languages. Handlers use Sigma to share and deploy log-based detection logic across platforms." },
  { term:"YARA Rules", definition:"A pattern-matching language for identifying and classifying malware based on textual or binary signatures in files and memory. Handlers write YARA rules to hunt for known malicious samples during investigation." },
  { term:"Threat Hunting Hypothesis", definition:"A testable assumption about adversary presence or behavior that guides proactive searching through data. Hypothesis-driven hunting, often based on ATT&CK techniques, seeks threats that evade automated detection." },
  { term:"Honeypot", definition:"A decoy system deliberately exposed to attract and observe attackers, generating high-fidelity alerts when touched. It provides threat intelligence and early warning without risking production assets." },
  { term:"Honeytoken", definition:"A piece of fake data, such as a bogus credential, file, or database record, planted to trigger an alert when accessed. Any interaction strongly indicates unauthorized activity, aiding detection of insiders and intruders." },
  { term:"Live Response", definition:"Collecting evidence and triage data from a running system without shutting it down, capturing volatile state like memory, network connections, and processes. It is essential when powering off would destroy critical evidence or disrupt operations." },
  { term:"Memory Acquisition", definition:"Capturing a bit-for-bit image of a system's RAM to preserve volatile artifacts such as running malware, encryption keys, and network sockets. Tools like FTK Imager or WinPmem create the image for later memory forensics." },
  { term:"Disk Imaging", definition:"Creating a forensic, bit-by-bit copy of storage media, validated by hashing, so investigation occurs on the copy rather than the original. It preserves the evidentiary integrity of the source drive." },
  { term:"Legal Hold", definition:"A directive to preserve all potentially relevant data and evidence when litigation or investigation is reasonably anticipated. It suspends normal deletion and retention policies to prevent spoliation." },
  { term:"eDiscovery", definition:"The process of identifying, collecting, and producing electronically stored information for legal proceedings. In IR it intersects with evidence handling when incidents lead to litigation or regulatory action." },
  { term:"Write Blocker", definition:"A hardware or software device that permits reading a storage medium while preventing any writes to it. Handlers use it during acquisition to guarantee the original evidence is not altered." },
  { term:"Forensic Hashing (MD5/SHA)", definition:"Computing cryptographic hashes of evidence before and after acquisition to prove the copy is identical and unaltered. Matching hashes verify integrity and support admissibility." },
  { term:"Ransomware Decryptor", definition:"A tool that reverses ransomware encryption, sometimes released by researchers or law enforcement when key flaws or seized keys exist. Handlers check repositories like No More Ransom before considering payment during recovery." },
  { term:"Double Extortion", definition:"A ransomware tactic where attackers exfiltrate data before encrypting it, then threaten to publish it unless paid. It pressures victims even when they can restore from backups, complicating containment and breach notification." },
  { term:"Triple Extortion", definition:"An escalation of double extortion adding a third pressure vector, such as DDoS attacks or direct threats to the victim's customers and partners. It maximizes leverage to force ransom payment." },
  { term:"Data Exfiltration Detection", definition:"Identifying unauthorized data transfer out of the network through indicators like large outbound flows, unusual destinations, or DLP alerts. Detecting exfiltration is critical for breach scoping and notification decisions." },
  { term:"Command and Control (C2)", definition:"The infrastructure and channel an attacker uses to remotely direct compromised systems. Detecting and disrupting C2, a core kill-chain stage, cuts the adversary's control and halts further tasking." },
  { term:"Beaconing", definition:"The periodic, often regular network callbacks a compromised host makes to its C2 server. Handlers detect beaconing by analyzing timing regularity and destination patterns in network traffic." },
  { term:"DNS Tunneling", definition:"Encoding data or C2 traffic within DNS queries and responses to bypass controls that permit DNS. Handlers detect it through anomalous query volume, length, and entropy in DNS logs." },
  { term:"Pass-the-Hash", definition:"A lateral movement technique where an attacker authenticates using a captured NTLM password hash without knowing the plaintext. Detection focuses on anomalous authentication patterns and credential reuse across hosts." },
  { term:"Pass-the-Ticket", definition:"A technique that reuses stolen Kerberos tickets to authenticate as a user without their password. It enables lateral movement within an Active Directory domain and is detected through ticket anomalies and event correlation." },
  { term:"Living off the Land (LOLBins)", definition:"Attacker use of legitimate, preinstalled system binaries and tools like PowerShell, WMIC, and certutil to perform malicious actions while evading detection. Handlers hunt for abnormal parameters and parent-child process anomalies." },
  { term:"Persistence via Run Keys", definition:"Malware maintaining survival across reboots by adding entries to Windows registry Run/RunOnce keys. Handlers examine these autostart locations during investigation to find and remove persistence." },
  { term:"Persistence via Scheduled Tasks", definition:"Attackers create or modify scheduled tasks so malicious code re-executes on triggers or intervals. It is a common persistence and privilege mechanism handlers review during eradication." },
  { term:"Persistence via WMI", definition:"Adversaries abuse Windows Management Instrumentation event subscriptions to run code persistently and stealthily. Because WMI persistence leaves few file artifacts, handlers query WMI repositories to detect it." },
  { term:"Privilege Escalation", definition:"Techniques an attacker uses to gain higher permissions, moving from a normal user to administrator or SYSTEM. Detecting escalation is key because elevated access enables broader compromise and defense evasion." },
  { term:"Credential Dumping (LSASS)", definition:"Extracting account credentials from the memory of the Windows LSASS process, often with tools like Mimikatz. Handlers monitor for suspicious LSASS access and protect it with credential guard controls." },
  { term:"Golden Ticket", definition:"A forged Kerberos Ticket-Granting Ticket created using a stolen KRBTGT account hash, granting an attacker near-unlimited domain access. Recovery typically requires resetting the KRBTGT password twice to invalidate forged tickets." },
  { term:"Silver Ticket", definition:"A forged Kerberos service ticket created from a compromised service account's hash, granting access to a specific service without contacting the domain controller. It is stealthier than a Golden Ticket but more limited in scope." },
  { term:"Kerberoasting", definition:"An attack that requests service tickets for accounts with SPNs and cracks them offline to recover service account passwords. Handlers detect abnormal TGS request volumes and enforce strong service account passwords." },
  { term:"DoS vs DDoS", definition:"A Denial of Service attack originates from a single source, while a Distributed Denial of Service uses many compromised hosts to overwhelm a target. DDoS is harder to mitigate because traffic comes from countless distributed sources." },
  { term:"Volumetric DDoS", definition:"An attack that saturates the target's bandwidth with massive traffic volume, measured in bits per second. Mitigation typically requires upstream scrubbing or cloud-based absorption of the flood." },
  { term:"Protocol DDoS", definition:"An attack that exhausts server or network device resources by abusing protocol weaknesses, such as SYN floods consuming connection tables. It is measured in packets per second and mitigated at network devices and stateful defenses." },
  { term:"Application-Layer DDoS", definition:"An attack targeting layer 7 services with seemingly legitimate requests, such as HTTP floods, to exhaust application resources. Low-volume but hard to distinguish from real traffic, it requires behavioral filtering to mitigate." },
  { term:"Amplification/Reflection Attack", definition:"A DDoS technique that spoofs the victim's address and sends small queries to services like DNS or NTP, which reply with much larger responses aimed at the victim. The amplification factor multiplies attacker bandwidth against the target." },
  { term:"SYN Flood", definition:"A protocol attack that sends many TCP SYN packets without completing the handshake, exhausting the server's half-open connection table. Defenses include SYN cookies, rate limiting, and firewall connection limits." },
  { term:"Traffic Scrubbing", definition:"Routing incoming traffic through a filtering service that removes malicious DDoS packets and forwards only clean traffic. It is a primary mitigation for large volumetric attacks." },
  { term:"Rate Limiting", definition:"Restricting the number of requests a source can make in a given period to blunt floods and brute-force attempts. It is a containment and mitigation control for DoS and abusive traffic." },
  { term:"ARP Spoofing", definition:"Sending forged ARP messages to associate an attacker's MAC with a legitimate IP, enabling interception on a local network. It underlies man-in-the-middle attacks and is detected through ARP table anomalies." },
  { term:"DNS Cache Poisoning", definition:"Injecting forged records into a DNS resolver's cache so users are redirected to malicious sites. Handlers mitigate it with DNSSEC and by monitoring for unexpected resolution changes." },
  { term:"Man-in-the-Middle (MITM)", definition:"An attack where the adversary secretly relays and possibly alters communication between two parties who believe they talk directly. It enables eavesdropping and credential theft, mitigated by strong encryption and certificate validation." },
  { term:"Rogue AP / Evil Twin", definition:"An unauthorized wireless access point, often impersonating a legitimate SSID, used to lure clients and intercept traffic. Handlers detect them through wireless scanning and rogue AP detection systems." },
  { term:"Cross-Site Scripting (XSS)", definition:"An attack that injects malicious script into web pages viewed by other users, enabling session theft or defacement. Handlers investigate reflected, stored, and DOM-based variants and remediate with output encoding." },
  { term:"Cross-Site Request Forgery (CSRF)", definition:"An attack that tricks an authenticated user's browser into submitting unwanted actions to a site where they are logged in. Mitigations include anti-CSRF tokens and SameSite cookies." },
  { term:"Server-Side Request Forgery (SSRF)", definition:"An attack that abuses a server to make requests to internal or unintended resources on the attacker's behalf. It is frequently used to reach cloud metadata services and internal systems." },
  { term:"Web Shell", definition:"A malicious script uploaded to a web server that gives an attacker remote command execution and persistence. Handlers hunt for anomalous files in web directories and unusual web server child processes." },
  { term:"WAF Bypass", definition:"Techniques attackers use to evade Web Application Firewall rules, such as encoding, obfuscation, or fragmentation. Handlers tune WAF rules and correlate application logs to catch bypass attempts." },
  { term:"AWS CloudTrail (IR)", definition:"An AWS service that logs API calls and account activity, serving as a primary evidence source for cloud incident investigation. Handlers analyze CloudTrail to reconstruct attacker actions and identify compromised credentials." },
  { term:"Amazon GuardDuty", definition:"An AWS threat detection service that analyzes logs like CloudTrail, VPC Flow, and DNS to surface malicious or anomalous activity. It provides findings that feed cloud incident triage and response." },
  { term:"SLA vs OLA (IR)", definition:"A Service Level Agreement defines commitments to external customers, while an Operational Level Agreement defines internal support commitments between teams. Both set the response and resolution timeframes IR must meet." },
  { term:"GDPR 72-Hour Notification", definition:"The GDPR requirement that a personal data breach be reported to the supervisory authority within 72 hours of becoming aware of it. It drives IR timelines for breach scoping, documentation, and regulator communication." },
  { term:"Simulation Exercise", definition:"A partially operational drill that injects realistic events into a controlled environment to test detection and response actions. It goes beyond discussion by exercising some tools and procedures hands-on." },
  { term:"Full-Scale Exercise", definition:"A comprehensive, live exercise that mobilizes people, processes, and technology as if a real incident were occurring. It is the most realistic and resource-intensive way to validate IR readiness." },
  { term:"Business Impact Analysis (BIA)", definition:"A process that identifies critical business functions and the impact of their disruption over time. It informs IR prioritization and continuity planning by ranking what must be recovered first." },
  { term:"Recovery Time Objective (RTO)", definition:"The maximum acceptable duration for restoring a system or process after disruption. It guides recovery sequencing and resource allocation during the recovery phase." },
  { term:"Recovery Point Objective (RPO)", definition:"The maximum acceptable amount of data loss measured in time, defining how current backups must be. It dictates backup frequency and shapes data restoration decisions after an incident." },
  { term:"Maximum Tolerable Downtime (MTD)", definition:"The total time a business function can be unavailable before causing unacceptable harm. RTO plus the time to resume normal operation must remain within the MTD." },
  { term:"Crisis Communication Plan", definition:"A predefined framework for internal and external messaging during a major incident, specifying spokespersons, approval flows, and templates. It ensures accurate, consistent, and timely communication to stakeholders and the public." },
  { term:"Incident Response Plan (IRP)", definition:"The formal document defining the organization's approach, roles, procedures, and authority for handling incidents. It is a core preparation artifact that guides consistent, repeatable response." },
  { term:"Indicator Lifecycle", definition:"The stages an indicator passes through: reporting, vetting, publishing, use in detection, and eventual retirement as it ages out. Managing this lifecycle keeps detection accurate and reduces false positives from stale IOCs." },
  { term:"Confidence and Reliability Scoring", definition:"Rating intelligence by source reliability and information credibility, often with the Admiralty/NATO grading scale. It helps handlers weigh how much trust to place in a given indicator or report." },
  { term:"Cuckoo Sandbox", definition:"An automated malware analysis system that detonates suspicious files in an isolated environment and reports their behavior. Handlers use sandbox output to derive IOCs and understand malware capabilities." },
  { term:"Static vs Dynamic Malware Analysis", definition:"Static analysis inspects malware without executing it, examining code, strings, and structure, while dynamic analysis observes behavior during execution in a sandbox. Combining both yields fuller understanding of a sample for response." },
  { term:"Memory Forensics (Volatility)", definition:"Analyzing a captured RAM image with tools like the Volatility Framework to recover processes, network connections, injected code, and credentials. It is essential for investigating fileless and in-memory threats." },
  { term:"Timeline Analysis (Super Timeline)", definition:"Correlating timestamps from filesystem, logs, and artifacts into a unified chronological view of events, often built with tools like Plaso. It helps handlers reconstruct the sequence of attacker actions." },
  { term:"MFT (Master File Table) Analysis", definition:"Examining the NTFS Master File Table to recover file metadata, timestamps, and evidence of deleted or created files. It supports timeline reconstruction and detection of attacker file activity." },
  { term:"Prefetch Analysis", definition:"Reviewing Windows Prefetch files to determine which executables ran, when, and how often. Handlers use prefetch artifacts as evidence of program execution during investigations." },
  { term:"Shellbags", definition:"Registry artifacts recording folders a user browsed in Windows Explorer, including now-deleted or external locations. They provide evidence of folder access useful in insider and intrusion investigations." },
  { term:"Amcache/Shimcache", definition:"Windows registry and cache artifacts that record evidence of program execution and application compatibility. Handlers analyze them to identify malicious binaries that ran, even if later deleted." },
  { term:"Windows Event ID 4625", definition:"The security log event recording a failed logon attempt, useful for spotting brute-force and password-spraying attacks. Handlers correlate spikes of 4625 events with source addresses and account names." },
  { term:"Windows Event ID 4624", definition:"The security log event recording a successful logon, including the logon type that reveals interactive, network, or remote access. Handlers analyze it to trace attacker authentication and lateral movement." },
  { term:"Windows Event ID 4688", definition:"The security log event recording new process creation, optionally including the command line. It is a key artifact for detecting malicious execution and LOLBin abuse." },
  { term:"Sysmon", definition:"A Windows system monitor that logs detailed events like process creation, network connections, and file changes with rich context. Handlers deploy it to enhance endpoint visibility and enable ATT&CK-aligned detection." },
  { term:"EDR (Endpoint Detection and Response)", definition:"A tool that continuously records endpoint activity, detects threats, and enables remote investigation and containment. Handlers rely on EDR for host visibility, isolation, and threat hunting during incidents." },
  { term:"NDR (Network Detection and Response)", definition:"A capability that monitors network traffic with behavioral analytics to detect threats such as lateral movement and C2. It complements endpoint tools by catching activity visible only on the wire." },
  { term:"UEBA", definition:"User and Entity Behavior Analytics establishes baselines of normal behavior and flags anomalies indicating compromise or insider threat. It helps handlers detect subtle attacks that signature-based tools miss." },
  { term:"SIEM Correlation Rule", definition:"Logic in a SIEM that combines multiple log events to detect patterns indicative of an attack. Well-tuned correlation rules reduce noise and surface actionable incidents for handlers." },
  { term:"False Positive vs False Negative", definition:"A false positive is a benign event wrongly flagged as malicious, while a false negative is a real threat that goes undetected. Handlers tune detections to balance both, since each carries operational and security costs." },
  { term:"Indicators Enrichment", definition:"Augmenting raw indicators with context such as geolocation, WHOIS, reputation, and related campaigns. Enrichment speeds triage by helping handlers judge severity and relevance quickly." },
  { term:"Pivoting (Analysis)", definition:"Using one known indicator or artifact to discover related infrastructure, samples, or activity. Analytical pivoting expands understanding of an intrusion and uncovers additional attacker assets." },
  { term:"Attribution", definition:"The process of associating an intrusion with a specific threat actor or group based on TTPs, infrastructure, and intelligence. While useful for context, handlers treat attribution cautiously and avoid letting it delay containment." },
  { term:"Data Loss Prevention (DLP)", definition:"Controls that monitor and block unauthorized movement of sensitive data across endpoints, networks, and cloud. DLP alerts are key inputs for detecting exfiltration during incidents." },
  { term:"Breach Notification Assessment", definition:"Determining whether an incident meets legal or contractual thresholds requiring notification to regulators, customers, or partners. It weighs data sensitivity, scope, and jurisdictional rules to guide disclosure decisions." },
  { term:"Payment Card Incident (PCI DSS)", definition:"An incident involving cardholder data that triggers PCI DSS response obligations, including forensic investigation and card brand notification. Handlers must engage a PFI when required and follow strict evidence procedures." },
  { term:"Incident Scoping", definition:"Determining the full extent of an incident, including all affected systems, accounts, and data. Accurate scoping prevents premature closure and ensures eradication covers every foothold." },
  { term:"Backup Integrity Validation", definition:"Verifying that backups are complete, uncompromised, and restorable before relying on them for recovery. It guards against restoring malware or corrupted data, especially after ransomware." },
  { term:"Purple Teaming", definition:"A collaborative exercise where offensive red and defensive blue teams work together to improve detection and response. It validates and strengthens IR controls against realistic adversary techniques." },
  { term:"Cyber Threat Intelligence Feed", definition:"A stream of indicators and context, commercial or open-source, integrated into security tools for detection and enrichment. Handlers vet and tune feeds to maximize relevance and minimize false positives." },
  { term:"Kill Switch (Malware)", definition:"A condition or domain that, when present or reachable, halts malware execution, as seen with WannaCry. Handlers may exploit a discovered kill switch to contain an outbreak rapidly." },
  { term:"Golden Image / Reimaging", definition:"Rebuilding a compromised system from a known-clean baseline image during recovery. It ensures eradication of hidden persistence by replacing the entire system rather than patching in place." }
];
GLOSSARY_ECIH.sort((a, b) => a.term.localeCompare(b.term, undefined, { sensitivity: 'base' }));
